const WebSocket = require('ws');

const wss = new WebSocket.Server({ port: 8080 });

// Basic Game State
const gameState = {
    players: {}, // { playerId: { name: 'PlayerN', resources: 100, ws: WebSocket } }
    units: {},   // { unitId: { type: 'infantry', ownerId: 'playerId1', position: {x,y}, health: 100 } }
    buildings: {}, // { buildingId: { type: 'barracks', ownerId: 'playerId1', position: {x,y}, health: 200 } }
    nextPlayerId: 1,
    nextUnitId: 1,
    nextBuildingId: 1,
    mapWidth: 100,
    mapHeight: 100
};

// Utility to broadcast game state to all connected clients
function broadcastGameState() {
    const stateToSend = JSON.stringify(gameState); // Send full state for simplicity
    for (const playerId in gameState.players) {
        const player = gameState.players[playerId];
        if (player.ws.readyState === WebSocket.OPEN) {
            player.ws.send(stateToSend);
        }
    }
}

wss.on('connection', ws => {
    // Assign a new player ID
    const playerId = `player${gameState.nextPlayerId++}`;
    console.log(`Player ${playerId} connected.`);

    gameState.players[playerId] = {
        id: playerId,
        name: `Player ${playerId.substring(6)}`,
        resources: 500,
        ws: ws // Store the WebSocket instance for direct communication
    };

    // Send initial game state to the new player
    ws.send(JSON.stringify({ type: 'init', playerId: playerId, gameState: gameState }));
    broadcastGameState(); // Inform all others about the new player

    ws.on('message', message => {
        try {
            const command = JSON.parse(message);
            // Basic authentication: ensure the command comes from the player it claims to be from.
            if (command.ownerId !== playerId) {
                console.log(`Unauthorized command from ${playerId} for ownerId ${command.ownerId}`);
                ws.send(JSON.stringify({ type: 'error', message: 'Unauthorized command' }));
                return;
            }

            console.log(`Command from ${playerId}: ${command.type}`);

            switch (command.type) {
                case 'build':
                    // Payload: { ownerId, unitType, position: {x, y} }
                    handleBuildCommand(command.payload);
                    break;
                case 'move':
                    // Payload: { ownerId, unitIds: [], targetPosition: {x, y} }
                    handleMoveCommand(command.payload);
                    break;
                case 'attack':
                    // Payload: { ownerId, attackingUnitIds: [], targetId: 'unitX' | 'buildingY' }
                    handleAttackCommand(command.payload);
                    break;
                case 'chat':
                    // Payload: { ownerId, message: 'hello world' }
                    handleChatCommand(command.payload);
                    break;
                default:
                    console.log(`Unknown command type: ${command.type}`);
                    ws.send(JSON.stringify({ type: 'error', message: 'Unknown command' }));
                    break;
            }
            // After processing any command, broadcast the updated state
            broadcastGameState();

        } catch (error) {
            console.error('Failed to parse message or process command:', error);
            ws.send(JSON.stringify({ type: 'error', message: 'Invalid command format' }));
        }
    });

    ws.on('close', () => {
        console.log(`Player ${playerId} disconnected.`);
        // Remove player from game state
        delete gameState.players[playerId];
        // Remove units/buildings owned by this player (optional, depends on game rules)
        for (const unitId in gameState.units) {
            if (gameState.units[unitId].ownerId === playerId) {
                delete gameState.units[unitId];
            }
        }
        for (const buildingId in gameState.buildings) {
            if (gameState.buildings[buildingId].ownerId === playerId) {
                delete gameState.buildings[buildingId];
            }
        }
        broadcastGameState();
    });

    ws.on('error', error => {
        console.error(`WebSocket error for player ${playerId}:`, error);
    });
});

// --- Command Handlers ---

function handleBuildCommand(payload) {
    const { ownerId, buildingType, position } = payload;
    const player = gameState.players[ownerId];

    if (!player || !buildingType || !position) {
        console.log('Invalid build command payload.');
        return;
    }

    // Basic validation:
    // Check resources
    const buildingCost = 100; // Example cost
    if (player.resources < buildingCost) {
        console.log(`${player.name} does not have enough resources to build ${buildingType}.`);
        return;
    }

    // Check if position is valid/available (simple check)
    if (position.x < 0 || position.x >= gameState.mapWidth ||
        position.y < 0 || position.y >= gameState.mapHeight) {
        console.log(`Invalid build position for ${buildingType} at (${position.x}, ${position.y}).`);
        return;
    }

    // Create new building
    const buildingId = `building${gameState.nextBuildingId++}`;
    gameState.buildings[buildingId] = {
        id: buildingId,
        type: buildingType,
        ownerId: ownerId,
        position: { x: position.x, y: position.y },
        health: 200
    };
    player.resources -= buildingCost;
    console.log(`${player.name} built a ${buildingType} at (${position.x}, ${position.y}).`);
}

function handleMoveCommand(payload) {
    const { ownerId, unitIds, targetPosition } = payload;
    const player = gameState.players[ownerId];

    if (!player || !unitIds || !Array.isArray(unitIds) || !targetPosition) {
        console.log('Invalid move command payload.');
        return;
    }

    // Check if target position is valid
    if (targetPosition.x < 0 || targetPosition.x >= gameState.mapWidth ||
        targetPosition.y < 0 || targetPosition.y >= gameState.mapHeight) {
        console.log(`Invalid target position for move: (${targetPosition.x}, ${targetPosition.y}).`);
        return;
    }

    unitIds.forEach(unitId => {
        const unit = gameState.units[unitId];
        if (unit && unit.ownerId === ownerId) {
            unit.position = { x: targetPosition.x, y: targetPosition.y }; // Instantaneous move
            console.log(`Unit ${unitId} moved to (${targetPosition.x}, ${targetPosition.y}).`);
        } else {
            console.log(`Unit ${unitId} not found or not owned by ${ownerId}.`);
        }
    });
}

function handleAttackCommand(payload) {
    const { ownerId, attackingUnitIds, targetId } = payload;
    const player = gameState.players[ownerId];

    if (!player || !attackingUnitIds || !Array.isArray(attackingUnitIds) || !targetId) {
        console.log('Invalid attack command payload.');
        return;
    }

    const targetUnit = gameState.units[targetId];
    const targetBuilding = gameState.buildings[targetId];
    const target = targetUnit || targetBuilding;

    if (!target) {
        console.log(`Target ${targetId} not found.`);
        return;
    }
    if (target.ownerId === ownerId) {
        console.log(`Cannot attack own unit/building ${targetId}.`);
        return;
    }

    let totalDamage = 0;
    attackingUnitIds.forEach(unitId => {
        const attacker = gameState.units[unitId];
        if (attacker && attacker.ownerId === ownerId) {
            // Simulate damage. In a real game, this would involve range checks, attack speed, etc.
            totalDamage += 10; // Example damage
            console.log(`Unit ${unitId} attacked ${targetId}.`);
        } else {
            console.log(`Attacking unit ${unitId} not found or not owned by ${ownerId}.`);
        }
    });

    if (totalDamage > 0) {
        target.health -= totalDamage;
        console.log(`${targetId} took ${totalDamage} damage. Health: ${target.health}`);
        if (target.health <= 0) {
            console.log(`${targetId} was destroyed!`);
            if (targetUnit) {
                delete gameState.units[targetId];
            } else if (targetBuilding) {
                delete gameState.buildings[targetId];
            }
        }
    }
}

function handleChatCommand(payload) {
    const { ownerId, message } = payload;
    const playerName = gameState.players[ownerId] ? gameState.players[ownerId].name : ownerId;
    const chatMessage = {
        type: 'chat',
        sender: playerName,
        message: message,
        timestamp: Date.now()
    };

    // Broadcast chat message to all players
    for (const playerId in gameState.players) {
        const player = gameState.players[playerId];
        if (player.ws.readyState === WebSocket.OPEN) {
            player.ws.send(JSON.stringify(chatMessage));
        }
    }
    console.log(`Chat from ${playerName}: ${message}`);
}


